mapper.insert:
/* sample.BoardInsert 인서트 */
SELECT BNO_BOARD_SEQ.NEXTVAL FROM DUAL
INSERT INTO TOAST_BOARD(BOARD_NO, TITLE, CONTENT, WRITER, UPD_ID, UPD_DTM, REG_ID, REG_DTM) VALUES (#{BNOSEQ}, #{title}, #{content}, '김욱', '김욱', SYSDATE, '김욱', SYSDATE)

mapper.select:
/* sample.BoardItem 리스트 상세 보기 */
SELECT TITLE
     , CONTENT 
  FROM TOAST_BOARD 
 WHERE BOARD_NO = #{board_no}
   AND TITLE = #{title}
